/** Predefined ophthalmic exam finding options for quick documentation. */

import { mergeStringListsUnique, normalizeCatalogToken } from './clinicalCatalog';

export const CUSTOM_OPHTHALMIC_FINDINGS_STORAGE_KEY = 'emr_custom_ophthalmic_findings_v1';
export const OPHTHALMIC_FINDINGS_UPDATED_EVENT = 'emr-ophthalmic-findings-updated';

export const EYE_SIDES = ['OD', 'OS', 'OU'];

/** Exam form fields stored as { right, left } per eye. */
export const EXAM_FINDING_FIELD_KEYS = [
    'lids',
    'adnexa',
    'anterior_segment',
    'pupils',
    'ocular_motility',
    'posterior_segment',
    'neuro_ophthalmic',
];

const defaultFindingPair = () => ({ right: '', left: '' });

const EYE_PREFIX_RE = /^(OD|OS|OU|Right|Left)\s*:\s*(.*)$/i;

/** Normalize legacy string or per-eye object to { right, left }. */
export const normalizeFindingPair = (value) => {
    if (value && typeof value === 'object') {
        if ('right' in value || 'left' in value || 'od' in value || 'os' in value) {
            return {
                right: String(value.right ?? value.od ?? value.OD ?? '').trim(),
                left: String(value.left ?? value.os ?? value.OS ?? '').trim(),
            };
        }
    }
    if (typeof value === 'string') return splitLegacyFindingText(value);
    return defaultFindingPair();
};

/** Parse OD:/OS:/OU: prefixed lines; otherwise duplicate text to both eyes. */
export const splitLegacyFindingText = (text) => {
    const base = defaultFindingPair();
    const raw = String(text || '').trim();
    if (!raw) return base;

    const buckets = { right: [], left: [], both: [] };
    let hasEyePrefix = false;

    for (const line of raw.split(/\n+/)) {
        const trimmed = line.trim();
        if (!trimmed) continue;
        const match = trimmed.match(EYE_PREFIX_RE);
        if (match) {
            hasEyePrefix = true;
            const token = match[1].toLowerCase();
            const content = match[2].trim();
            if (!content) continue;
            if (token === 'od' || token === 'right') buckets.right.push(content);
            else if (token === 'os' || token === 'left') buckets.left.push(content);
            else buckets.both.push(content);
        } else if (hasEyePrefix) {
            const target =
                buckets.right.length >= buckets.left.length ? buckets.right : buckets.left;
            if (target.length) target[target.length - 1] += ` ${trimmed}`;
        }
    }

    if (hasEyePrefix) {
        const join = (arr) => arr.join('\n');
        const shared = join(buckets.both);
        base.right = [join(buckets.right), shared].filter(Boolean).join('\n');
        base.left = [join(buckets.left), shared].filter(Boolean).join('\n');
        return base;
    }

    return { right: raw, left: raw };
};

export const hasFindingPairContent = (value) => {
    const pair = normalizeFindingPair(value);
    return Boolean(pair.right.trim() || pair.left.trim());
};

/** Format per-eye findings for reports, PDF, and portal (lang: en | ar). */
export const formatFindingPairForDisplay = (value, lang = 'en') => {
    const pair = normalizeFindingPair(value);
    if (!pair.right.trim() && !pair.left.trim()) return '';
    if (pair.right.trim() && pair.right.trim() === pair.left.trim()) {
        return pair.right.trim();
    }
    const odLabel = lang === 'ar' ? 'يمين (OD)' : 'OD';
    const osLabel = lang === 'ar' ? 'يسار (OS)' : 'OS';
    const lines = [];
    if (pair.right.trim()) lines.push(`${odLabel}: ${pair.right.trim()}`);
    if (pair.left.trim()) lines.push(`${osLabel}: ${pair.left.trim()}`);
    return lines.join('\n');
};

export const normalizeExamFindingFields = (data) => {
    if (!data || typeof data !== 'object') return {};
    const out = {};
    for (const key of EXAM_FINDING_FIELD_KEYS) {
        out[key] = normalizeFindingPair(data[key]);
    }
    return out;
};

export const buildDefaultExamFindings = () => {
    const out = {};
    for (const key of EXAM_FINDING_FIELD_KEYS) {
        out[key] = defaultFindingPair();
    }
    return out;
};

const readCustomFindingsStore = () => {
    try {
        const raw = localStorage.getItem(CUSTOM_OPHTHALMIC_FINDINGS_STORAGE_KEY);
        if (!raw) return { en: {}, ar: {} };
        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') return { en: {}, ar: {} };
        return {
            en: parsed.en && typeof parsed.en === 'object' ? parsed.en : {},
            ar: parsed.ar && typeof parsed.ar === 'object' ? parsed.ar : {},
        };
    } catch {
        return { en: {}, ar: {} };
    }
};

const writeCustomFindingsStore = (store) => {
    try {
        localStorage.setItem(CUSTOM_OPHTHALMIC_FINDINGS_STORAGE_KEY, JSON.stringify(store));
        window.dispatchEvent(new CustomEvent(OPHTHALMIC_FINDINGS_UPDATED_EVENT));
    } catch {
        console.warn('Unable to persist custom ophthalmic findings');
    }
};

/** Bundled options only (no clinician-added rows). */
export const getBundledFindingCategoryOptions = (categoryKey, lang = 'en') => {
    const category = OPHTHALMIC_FINDING_CATEGORIES[categoryKey];
    if (!category) return [];
    if (lang === 'ar' && Array.isArray(category.optionsAr) && category.optionsAr.length) {
        return category.optionsAr;
    }
    return category.options || [];
};

/** @returns {string[]} Custom findings for one category and language. */
export const getCustomFindingsForCategory = (categoryKey, lang = 'en') => {
    const bucket = lang === 'ar' ? readCustomFindingsStore().ar : readCustomFindingsStore().en;
    const list = bucket[categoryKey];
    return Array.isArray(list) ? list : [];
};

export const getFindingCategoryOptions = (categoryKey, lang = 'en') => {
    const bundled = getBundledFindingCategoryOptions(categoryKey, lang);
    const custom = getCustomFindingsForCategory(categoryKey, lang);
    return mergeStringListsUnique(bundled, custom);
};

export const normalizeFindingToken = (value) => normalizeCatalogToken(value);

export const findingMatchesCatalog = (text, categoryKey, lang = 'en') => {
    const token = normalizeFindingToken(text);
    if (!token) return true;
    return getFindingCategoryOptions(categoryKey, lang).some(
        (option) => normalizeFindingToken(option) === token
    );
};

/** Last non-empty line in free text, with OD:/OS:/OU: prefix stripped. */
export const extractLastFindingLine = (text) => {
    const lines = String(text || '')
        .split(/\n+/)
        .map((line) => line.trim())
        .filter(Boolean);
    if (!lines.length) return '';
    const last = lines[lines.length - 1];
    const match = last.match(EYE_PREFIX_RE);
    return (match ? match[2] : last).trim();
};

/**
 * Persist a clinician-typed finding for future dropdowns (deduped, case-insensitive).
 * @returns {string} Canonical stored label
 */
export const addCustomOphthalmicFinding = (categoryKey, text, lang = 'en') => {
    if (!OPHTHALMIC_FINDING_CATEGORIES[categoryKey]) {
        throw new Error('Unknown finding category');
    }
    const label = String(text || '').trim().replace(/\s+/g, ' ');
    if (!label) throw new Error('Finding text is required');
    if (findingMatchesCatalog(label, categoryKey, lang)) {
        return label;
    }

    const langKey = lang === 'ar' ? 'ar' : 'en';
    const store = readCustomFindingsStore();
    const bucket = { ...store[langKey] };
    const merged = mergeStringListsUnique(bucket[categoryKey] || [], [label]);
    bucket[categoryKey] = merged;
    writeCustomFindingsStore({ ...store, [langKey]: bucket });
    return label;
};

