export const appendFindingText = (current, finding, eye = null) => {
    if (!finding) return current || '';
    const prefix = eye && eye !== 'OU' ? `${eye}: ` : eye === 'OU' ? 'OU: ' : '';
    const line = `${prefix}${finding}`.trim();
    const base = (current || '').trim();
    if (!base) return line;
    if (base.split('\n').some((row) => row.trim() === line)) return base;
    return `${base}\n${line}`;
};
