/**
 * Arabic labels and clinical term glossary for report print / PDF output.
 * English keys are preserved in stored reports; translation runs at export time.
 */

/** Section keys omitted from print/PDF (demographics & physician stay in the form only). */
export const REPORT_SECTIONS_PRINT_EXCLUDE = new Set([
    'Patient Demographics',
    'Referring / Attending Physician',
    'Referring Physician',
]);

/** Preferred order for clinical sections on a single A5 print page. */
export const REPORT_CLINICAL_PRINT_ORDER = [
    'Reason for Visit',
    'Reason for Referral',
    'Examination Summary',
    'Diagnosis',
    'Plan / Recommendations',
];

export const isReportSectionPrintExcluded = (title) =>
    REPORT_SECTIONS_PRINT_EXCLUDE.has(String(title || '').trim());

/** Keys for non-template blocks (freeform, notes, signature) in sectionInclusion maps. */
export const REPORT_SECTION_INCLUSION_KEYS = {
    FREEFORM: '__freeform__',
    DOCTOR_NOTES: '__doctorNotes__',
    SIGNATURE: '__signature__',
    CLINICAL_APPENDIX: '__clinicalAppendix__',
};

/** Build a sectionInclusion map with every listed section defaulting to included. */
export const defaultReportSectionInclusion = (sectionKeys = []) => {
    const inclusion = {};
    sectionKeys.forEach((key) => {
        inclusion[key] = true;
    });
    inclusion[REPORT_SECTION_INCLUSION_KEYS.FREEFORM] = true;
    inclusion[REPORT_SECTION_INCLUSION_KEYS.DOCTOR_NOTES] = true;
    inclusion[REPORT_SECTION_INCLUSION_KEYS.SIGNATURE] = true;
    inclusion[REPORT_SECTION_INCLUSION_KEYS.CLINICAL_APPENDIX] = true;
    return inclusion;
};

/**
 * Whether a section/block should appear in print/PDF.
 * When sectionInclusion is set, user toggles win; otherwise legacy print exclusions apply.
 */
export const isReportSectionIncluded = (title, sectionInclusion) => {
    if (sectionInclusion != null && typeof sectionInclusion === 'object') {
        if (Object.prototype.hasOwnProperty.call(sectionInclusion, title)) {
            return sectionInclusion[title] !== false;
        }
        return true;
    }
    return !isReportSectionPrintExcluded(title);
};

