export const translateReportSectionTitle = (title, lang = 'en') => {
    if (!title || lang !== 'ar') return title;
    return REPORT_SECTION_TITLES_AR[title] || title;
};

export const translateReportDocumentTitle = (title, lang = 'en') => {
    if (!title || lang !== 'ar') return title;
    const trimmed = String(title).trim();
    return REPORT_DOCUMENT_TITLES_AR[trimmed] || REPORT_DOCUMENT_TITLES_AR[trimmed.toUpperCase()] || trimmed;
};

/** Replace known English clinical labels in report body text for Arabic print. */
export const translateReportBodyForPrint = (text, lang = 'en') => {
    if (!text || lang !== 'ar') return text;
    let out = String(text);
    for (const [en, ar] of CLINICAL_PHRASE_REPLACEMENTS) {
        out = out.split(en).join(ar);
    }
    return out;
};

export const localizeReportBlock = (block, lang = 'en') => {
    if (!block) return block;
    return {
        ...block,
        title: block.title ? translateReportSectionTitle(block.title, lang) : block.title,
        body: translateReportBodyForPrint(block.body, lang),
    };
};

export const localizeReportBlocks = (blocks, lang = 'en') => {
    if (!Array.isArray(blocks) || lang !== 'ar') return blocks || [];
    return blocks.map((b) => localizeReportBlock(b, lang));
};
