/**
 * Noto Sans Arabic for jsPDF (SIL Open Font License 1.1).
 * Regenerate: node scripts/generate-pdf-arabic-font.mjs
 */
export const PDF_ARABIC_FONT_VFS_NAME = 'NotoSansArabic-Regular.ttf';
export const PDF_ARABIC_FONT_FAMILY = 'NotoSansArabic';

const FONT_BASE64 = '';

let registeredDocs = new WeakSet();

/** Register Arabic font on this jsPDF instance (idempotent). */
export function registerPdfArabicFont(doc) {
    if (!doc || registeredDocs.has(doc)) return;
    doc.addFileToVFS(PDF_ARABIC_FONT_VFS_NAME, FONT_BASE64);
    doc.addFont(PDF_ARABIC_FONT_VFS_NAME, PDF_ARABIC_FONT_FAMILY, 'normal');
    registeredDocs.add(doc);
}
