const PDF_PAGE_FORMAT = 'a5';
/** A5 portrait: ~1cm from the physical left edge (content starts here). */
const PRINT_MARGIN_LEFT = 10;
/** ~3cm right gutter (binding / no-print zone); keeps right-side QR inside the printable strip. */
const PRINT_MARGIN_RIGHT = 30;
const PRINT_MARGIN = { left: PRINT_MARGIN_LEFT, right: PRINT_MARGIN_RIGHT };
const COMPACT_CELL_PADDING = { top: 1.5, right: 1.5, bottom: 1.5, left: 1.5 };

const createPdfDoc = () => new jsPDF({ unit: 'mm', format: PDF_PAGE_FORMAT, orientation: 'portrait' });
const getContentWidth = (pageWidth) => pageWidth - PRINT_MARGIN_LEFT - PRINT_MARGIN_RIGHT;
const getContentCenterX = (pageWidth) => PRINT_MARGIN_LEFT + getContentWidth(pageWidth) / 2;
const compactTableStyles = (fontSize = 8) => ({
    fontSize,
    cellPadding: COMPACT_CELL_PADDING,
    overflow: 'ellipsize',
    minCellHeight: fontSize <= 8 ? 4.6 : 5.4,
});
const compactHeadStyles = (fontSize = 8) => ({
    fillColor: [0, 128, 128],
    textColor: 255,
    fontStyle: 'bold',
    fontSize,
    cellPadding: COMPACT_CELL_PADDING,
    overflow: 'ellipsize',
});
const neutralMedicationHeadStyles = (fontSize = 8) => ({
    fillColor: [229, 231, 235],
    textColor: [17, 24, 39],
    fontStyle: 'bold',
    fontSize,
    cellPadding: COMPACT_CELL_PADDING,
    overflow: 'ellipsize',
});

/** Header-band QR pair (Facebook left, portal right) beside patient / date / reference lines. */
export const PDF_QR_SIZE_MM = 11;
const PDF_HEADER_QR_PAIR_GAP_MM = 2;
const PDF_HEADER_QR_TEXT_GAP_MM = 3;
const PDF_HEADER_QR_BELOW_MM = 1;
const PDF_FOOTER_TEL_OFFSET_MM = 21;
const PDF_FOOTER_ADDR_OFFSET_MM = 14;
const PDF_CONTENT_CLEARANCE_ABOVE_FOOTER_MM = 6;

const getPdfBottomLayout = (pageHeight) => {
    const footerTelY = pageHeight - PDF_FOOTER_TEL_OFFSET_MM;
    const footerAddrY = pageHeight - PDF_FOOTER_ADDR_OFFSET_MM;
    const contentMaxY = footerTelY - PDF_CONTENT_CLEARANCE_ABOVE_FOOTER_MM;
    return {
        footerTelY,
        footerAddrY,
        contentMaxY,
        bottomMargin: pageHeight - contentMaxY,
    };
};

const getPdfTableMargins = (doc) => {
    const pageHeight = doc.internal.pageSize.getHeight();
    const { bottomMargin } = getPdfBottomLayout(pageHeight);
    return { left: PRINT_MARGIN_LEFT, right: PRINT_MARGIN_RIGHT, bottom: bottomMargin };
};

const ensurePdfVerticalSpace = (doc, pageWidth, isArabic, currentY, neededMm) => {
    const pageHeight = doc.internal.pageSize.getHeight();
    const { contentMaxY } = getPdfBottomLayout(pageHeight);
    if (currentY + neededMm <= contentMaxY) return currentY;
    doc.addPage(PDF_PAGE_FORMAT, 'portrait');
    addHeader(doc, pageWidth, isArabic);
    return 45;
};

const stampFixedPageChrome = (doc, pageWidth, isArabic = false) => {
    const total = doc.internal.getNumberOfPages();
    for (let page = 1; page <= total; page += 1) {
        doc.setPage(page);
        addFooter(doc, pageWidth, isArabic);
    }
};

const finalizePatientReportPdf = async (doc, pageWidth, isArabic, patientId, contentEndY) => {
    const pageHeight = doc.internal.pageSize.getHeight();
    const { contentMaxY } = getPdfBottomLayout(pageHeight);
    let sigY = contentEndY ?? 80;
    if (sigY > contentMaxY - 18) {
        doc.addPage(PDF_PAGE_FORMAT, 'portrait');
        addHeader(doc, pageWidth, isArabic);
        sigY = 45;
    }
    await addPhysicianSignatureToPdf(doc, pageWidth, sigY, {
        isArabic,
        maxY: contentMaxY,
    });
    await stampFixedPageChrome(doc, pageWidth, isArabic, patientId);
};

/**
 * Scale medication prescription table typography / padding by row count so
 * typical multi-med lists stay on one A5 portrait page with header + patient (incl. QRs) + steroid regimen + footer.
 * Thresholds: default ≤4, then progressively denser above 4, 6, 8, 10, and 14 rows.
 */
const getMedicationTableLayout = (rowCount, contentWidth) => {
    let bodyFont = 8;
    let headFont = 11;
    let cellPadding = COMPACT_CELL_PADDING;
    let minCellHeight = 4.6;
    if (rowCount > 14) {
        bodyFont = 5;
        headFont = 6;
        cellPadding = { top: 0.65, right: 0.75, bottom: 0.65, left: 0.75 };
        minCellHeight = 2.8;
    } else if (rowCount > 10) {
        bodyFont = 5.5;
        headFont = 6.5;
        cellPadding = { top: 0.8, right: 0.85, bottom: 0.8, left: 0.85 };
        minCellHeight = 3.05;
    } else if (rowCount > 8) {
        bodyFont = 6;
        headFont = 7;
        cellPadding = { top: 1, right: 1, bottom: 1, left: 1 };
        minCellHeight = 3.4;
    } else if (rowCount > 6) {
        bodyFont = 6.5;
        headFont = 8;
        cellPadding = { top: 1.15, right: 1.15, bottom: 1.15, left: 1.15 };
        minCellHeight = 3.7;
    } else if (rowCount > 4) {
        bodyFont = 7;
        headFont = 9;
        cellPadding = { top: 1.25, right: 1.25, bottom: 1.25, left: 1.25 };
        minCellHeight = 4.1;
    }
    const w0 = Math.round(contentWidth * 0.062);
    const w3 = Math.round(contentWidth * 0.152);
    const w2 = Math.round(contentWidth * 0.275);
    const w1 = Math.max(22, contentWidth - w0 - w2 - w3);
    return {
        bodyFont,
        headFont,
        cellPadding,
        minCellHeight,
        columnWidths: [w0, w1, w2, w3],
    };
};

