// Pre-generated QR data URLs cache (keyed by URL). Promises resolve to data URLs
// or null on error. We eagerly start generating the clinic-website QR so it is
// almost always ready by the time a user clicks Print.
const _qrCache = new Map();
const getQRDataURL = (url, options = {}) => {
    const key = `${url}::${options.dark || ''}`;
    if (!_qrCache.has(key)) {
        _qrCache.set(
            key,
            QRCode.toDataURL(url, {
                width: 200,
                margin: 1,
                color: { dark: options.dark || '#0e7490', light: '#ffffff' }
            }).catch((err) => {
                console.error('QR generation error:', err);
                return null;
            })
        );
    }
    return _qrCache.get(key);
};
// Warm caches: clinic-website QR (teal) and Facebook QR (Facebook blue)
getQRDataURL(getClinicWebsiteBase());
getQRDataURL(CLINIC_INFO.facebook, { dark: '#1877F2' });

/**
 * Build the URL that a patient can scan/visit on the clinic website to access
 * their personal records. If a patient id is given, deep-links into the portal.
 */
const buildPatientPortalURL = (patientId) => {
    const base = getClinicWebsiteBase().replace(/\/$/, '');
    return patientId ? `${base}/portal.html#id=${encodeURIComponent(patientId)}` : `${base}/`;
};

/** Render one QR image anchored at (x, y) with the given size (no captions). */
const _drawQRImage = (doc, dataURL, x, y, size) => {
    try {
        doc.addImage(dataURL, 'PNG', x, y, size, size);
    } catch (e) {
        console.error('addImage QR error', e);
    }
};

/** Layout for Facebook + portal QRs to the right of the patient / date / reference block. */
const getPatientHeaderQrLayout = (pageWidth, blockTopY) => {
    const size = PDF_QR_SIZE_MM;
    const pairGap = PDF_HEADER_QR_PAIR_GAP_MM;
    const xPortal = pageWidth - PRINT_MARGIN_RIGHT - size;
    const xFb = xPortal - pairGap - size;
    const y = blockTopY;
    const qrBandWidth = size * 2 + pairGap;
    const textMaxWidth = Math.max(40, getContentWidth(pageWidth) - qrBandWidth - PDF_HEADER_QR_TEXT_GAP_MM);
    const blockBottomY = y + size + PDF_HEADER_QR_BELOW_MM;
    return { size, xFb, xPortal, y, textMaxWidth, blockBottomY };
};

/**
 * Facebook (left) + patient portal (right) QRs in the patient-header vertical band.
 * Left QR edge stays at or right of PRINT_MARGIN_LEFT; right QR stays inside the printable strip.
 */
const addPatientHeaderQRs = async (doc, layout, patientId = null) => {
    const { size, xFb, xPortal, y } = layout;

    const fbDataURL = await getQRDataURL(CLINIC_INFO.facebook, { dark: '#1877F2' });
    if (fbDataURL) {
        _drawQRImage(doc, fbDataURL, xFb, y, size);
    }

    const websiteUrl = buildPatientPortalURL(patientId);
    const websiteDataURL = await getQRDataURL(websiteUrl);
    if (websiteDataURL) {
        _drawQRImage(doc, websiteDataURL, xPortal, y, size);
    }
};

const getPatientId = (patient) => {
    if (!patient || typeof patient !== 'object') return null;
    const v = patient.referenceId ?? patient.patientId ?? patient.patient_id ?? patient.patientID ?? patient.id;
    return v != null && String(v).trim() !== '' ? String(v).trim() : null;
};

/** Portal / QR id when `patient` is a string or object without id — from explicit print options. */
const resolvePortalPatientId = (patient, options = {}) => {
    const fromObj = getPatientId(patient);
    if (fromObj) return fromObj;
    const opt = options.patientId ?? options.referenceId;
    return opt != null && String(opt).trim() !== '' ? String(opt).trim() : null;
};

/** Reference / file id from a clinical, lab, or billing row when callers only pass patient name string. */
const patientIdFromRecord = (record) => {
    if (!record || typeof record !== 'object') return null;
    const v = record.referenceId ?? record.patientId ?? record.patient_id ?? record.patientID;
    return v != null && String(v).trim() !== '' ? String(v).trim() : null;
};

/** Merge explicit PDF options with id stored on the source record (examination, glasses, etc.). */
const resolvePatientFileIdForPdf = (options = {}, record = null) => {
    const { patientId = null, referenceId = null } = options;
    return patientId ?? referenceId ?? patientIdFromRecord(record) ?? null;
};

/** Legacy `print*(…, isArabic)` boolean third argument, or an options object with `isArabic`, `patientId`, etc. */
const mergeArabicOrPdfOptions = (arg) => {
    if (arg === true || arg === false) return { isArabic: arg };
    if (arg != null && typeof arg === 'object' && !Array.isArray(arg)) return { isArabic: false, ...arg };
    return { isArabic: false };
};

const mergeExamPdfOptions = (arg) => {
    if (arg != null && typeof arg === 'object' && !Array.isArray(arg)) return { ...arg };
    return {};
};

/** Shared exit path for generate*PDF helpers (save, print, or return doc for portal blob export). */
const emitPdfResult = (doc, fileName, { forPrint = false, returnDoc = false } = {}) => {
    if (returnDoc) return doc;
    if (forPrint) {
        doc.autoPrint();
        doc.output('dataurlnewwindow');
        return null;
    }
    doc.save(fileName);
    return fileName;
};

