/**
 * Generate a PDF report for a patient's visit/examination
 */
export const generateExaminationPDF = async (exam, patientName, options = {}) => {
    const { forPrint = false, returnDoc = false, patientId = null, referenceId = null } = options;
    const portalId = coalescePdfPatientReferenceId(exam, patientName, { patientId, referenceId });
    const patientForPdf = normalizePatientArgForPdf(patientName, portalId);
    const doc = createPdfDoc();
    const pageWidth = doc.internal.pageSize.getWidth();
    const centerX = getContentCenterX(pageWidth);
    const contentWidth = getContentWidth(pageWidth);

    addHeader(doc, pageWidth);

    // Title
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('EYE EXAMINATION REPORT', centerX, 48, { align: 'center', maxWidth: contentWidth });

    // Patient Info
    let currentY = await addPatientInfoBlock(doc, patientForPdf, PRINT_MARGIN_LEFT, 58, {
        pageWidth,
        recordDate: exam.date || exam.createdAt?.split('T')[0],
        patientId: portalId,
        referenceId: portalId,
        sourceRecord: exam,
    });

    // Visual Acuity
    if (exam.unaided_va) {
        doc.setFont('helvetica', 'bold');
        doc.text('Visual Acuity (Unaided):', PRINT_MARGIN_LEFT, currentY);
        doc.setFont('helvetica', 'normal');
        doc.text(
            `OD: ${exam.unaided_va?.right || '-'}   OS: ${exam.unaided_va?.left || '-'}`,
            PRINT_MARGIN_LEFT + 50,
            currentY,
            { maxWidth: contentWidth - 50 }
        );
        currentY += 10;
    }

    // Refraction
    if (exam.subjective) {
        doc.setFont('helvetica', 'bold');
        doc.text('Subjective Refraction:', PRINT_MARGIN_LEFT, currentY);
        currentY += 7;

        const refractionData = [
            ['Eye', 'Sph', 'Cyl', 'Axis', 'VA'],
            ['OD', exam.subjective.right?.sph || '-', exam.subjective.right?.cyl || '-', exam.subjective.right?.axis || '-', exam.subjective.right?.va || '-'],
            ['OS', exam.subjective.left?.sph || '-', exam.subjective.left?.cyl || '-', exam.subjective.left?.axis || '-', exam.subjective.left?.va || '-']
        ];

        autoTable(doc, {
            startY: currentY,
            head: [refractionData[0]],
            body: refractionData.slice(1),
            theme: 'striped',
            headStyles: compactHeadStyles(8),
            styles: { ...compactTableStyles(8), halign: 'center' },
            margin: getPdfTableMargins(doc),
        });
        currentY = doc.lastAutoTable.finalY + 10;
    }

    // IOP
    if (exam.iop) {
        doc.setFont('helvetica', 'bold');
        doc.text('Intraocular Pressure:', PRINT_MARGIN_LEFT, currentY);
        doc.setFont('helvetica', 'normal');
        doc.text(`OD: ${exam.iop.right || '-'} mmHg   OS: ${exam.iop.left || '-'} mmHg`, PRINT_MARGIN_LEFT + 50, currentY, { maxWidth: contentWidth - 50 });
        currentY += 12;
    }

    const clinicalSections = [
        ['Lids & Lashes', formatFindingPairForDisplay(exam.lids)],
        ['Adnexa & Orbit', formatFindingPairForDisplay(exam.adnexa)],
        ['Anterior Segment', formatFindingPairForDisplay(exam.anterior_segment)],
        ['Pupils', formatFindingPairForDisplay(exam.pupils)],
        ['Ocular Motility', formatFindingPairForDisplay(exam.ocular_motility)],
        ['Posterior Segment (Fundus)', formatFindingPairForDisplay(exam.posterior_segment)],
        ['Neuro-ophthalmic', formatFindingPairForDisplay(exam.neuro_ophthalmic)],
    ];
    for (const [label, value] of clinicalSections) {
        if (!value) continue;
        doc.setFont('helvetica', 'bold');
        doc.text(`${label}:`, PRINT_MARGIN_LEFT, currentY);
        currentY += 7;
        doc.setFont('helvetica', 'normal');
        doc.text(value, PRINT_MARGIN_LEFT, currentY, { maxWidth: contentWidth });
        currentY += doc.getTextDimensions(value, { maxWidth: contentWidth }).h + 8;
    }

    // Diagnosis
    if (exam.diagnosis) {
        doc.setFont('helvetica', 'bold');
        doc.text('Diagnosis:', PRINT_MARGIN_LEFT, currentY);
        currentY += 7;
        doc.setFont('helvetica', 'normal');
        doc.text(exam.diagnosis, PRINT_MARGIN_LEFT, currentY, { maxWidth: contentWidth });
        currentY += doc.getTextDimensions(exam.diagnosis, { maxWidth: contentWidth }).h + 10;
    }

    // Notes
    if (exam.notes) {
        doc.setFont('helvetica', 'bold');
        doc.text('Additional Notes:', PRINT_MARGIN_LEFT, currentY);
        currentY += 7;
        doc.setFont('helvetica', 'normal');
        doc.text(exam.notes, PRINT_MARGIN_LEFT, currentY, { maxWidth: contentWidth });
        currentY += doc.getTextDimensions(exam.notes, { maxWidth: contentWidth }).h + 8;
    }

    await finalizePatientReportPdf(doc, pageWidth, false, portalId, currentY);

    const fileName = `exam_report_${getPatientFileName(patientForPdf)}_${exam.id || Date.now()}.pdf`;
    return emitPdfResult(doc, fileName, { forPrint, returnDoc });
};

