/**
 * Generate a medication prescription PDF with Arabic support
 */
export const generateMedicationPDF = async (medications, patientName, options = {}) => {
    const { isArabic = false, forPrint = false, returnDoc = false, patientId = null, referenceId = null } = options;
    const medsArray = Array.isArray(medications) ? medications : [medications];
    const portalId = coalescePdfPatientReferenceId(medsArray[0], patientName, { patientId, referenceId });
    const patientForPdf = normalizePatientArgForPdf(patientName, portalId);
    const doc = createPdfDoc();
    const pageWidth = doc.internal.pageSize.getWidth();
    const centerX = getContentCenterX(pageWidth);
    const contentWidth = getContentWidth(pageWidth);
    const t = (key) => translations[isArabic ? 'ar' : 'en'][key] || key;

    addHeader(doc, pageWidth, isArabic);

    // Title
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text(t('medicationPrescription'), centerX, 48, { align: 'center', maxWidth: contentWidth });

    // Patient Info
    const patientBlockEndY = await addPatientInfoBlock(doc, patientForPdf, PRINT_MARGIN_LEFT, 58, {
        isArabic,
        pageWidth,
        recordDate: new Date().toISOString().split('T')[0],
        patientId: portalId,
        referenceId: portalId,
        sourceRecord: medsArray[0],
    });

    // Medications: one autoTable — single head row, one body row per medication (never split into multiple tables)
    const tableData = medsArray.map((med, idx) => buildMedicationPdfTableRow(med, idx, isArabic));

    if (medsArray.length > 0) {
        const layout = getMedicationTableLayout(medsArray.length, contentWidth);
        const [cw0, cw1, cw2, cw3] = layout.columnWidths;

        autoTable(doc, {
            startY: patientBlockEndY + 4,
            head: [[
                '#',
                t('medication'),
                t('frequency'),
                t('duration')
            ]],
            body: tableData,
            theme: 'grid',
            tableWidth: contentWidth,
            styles: {
                fontSize: layout.bodyFont,
                cellPadding: layout.cellPadding,
                overflow: 'linebreak',
                minCellHeight: layout.minCellHeight,
                valign: 'top',
            },
            headStyles: {
                ...neutralMedicationHeadStyles(layout.headFont),
                fontSize: layout.headFont,
                cellPadding: layout.cellPadding,
            },
            bodyStyles: {
                fontSize: layout.bodyFont,
                cellPadding: layout.cellPadding,
                overflow: 'linebreak',
                minCellHeight: layout.minCellHeight,
                valign: 'top',
            },
            columnStyles: {
                0: { cellWidth: cw0, halign: 'center' },
                1: { cellWidth: cw1, overflow: 'linebreak' },
                2: { cellWidth: cw2, overflow: 'linebreak' },
                3: { cellWidth: cw3, halign: 'center', overflow: 'linebreak' }
            },
            margin: getPdfTableMargins(doc),
        });
    }

    let contentEndY = doc.lastAutoTable?.finalY ?? patientBlockEndY;
    const hasNotes = medsArray.some(isTopicalSteroidMedication)
        || collectVisitLevelInstructions(medsArray, options).length > 0;
    if (hasNotes) {
        const labelY = (doc.lastAutoTable?.finalY ?? patientBlockEndY) + (medsArray.length > 6 ? 8 : 10);
        contentEndY = appendMedicationPdfNotes(doc, medsArray, labelY, contentWidth, {
            dense: medsArray.length > 6,
            isArabic,
            visitInstructions: options.visitInstructions,
        });
    }

    await finalizePatientReportPdf(doc, pageWidth, isArabic, portalId, contentEndY);

    const fileName = `medication_rx_${getPatientFileName(patientForPdf)}_${Date.now()}.pdf`;
    return emitPdfResult(doc, fileName, { forPrint, returnDoc });
};

