const formatMedTreatDate = (item) => item?.date_prescribed || item?.date || item?.createdAt?.split?.('T')?.[0] || '-';

/** Stable key so we can tell if a Med&Treat export list is for one patient only. */
const getMedTreatPatientKey = (item) => {
    const id = item?.patientId ?? item?.patient_id;
    if (id != null && String(id).trim() !== '') return `id:${String(id)}`;
    const name = (item?.patientName || '').trim().toLowerCase();
    return name ? `name:${name}` : '';
};

const allMedTreatItemsSamePatient = (items) => {
    if (!Array.isArray(items) || items.length === 0) return false;
    const keys = items.map(getMedTreatPatientKey);
    if (keys.some((k) => !k)) return false;
    return keys.every((k) => k === keys[0]);
};

/**
 * Typography for the summary tables (global 4-col or single-patient 3-col non-med block).
 * Scaled by row count so long lists stay on A5 where possible.
 */
const getMedTreatSummaryTableLayout = (rowCount) => {
    let fontSize = 7;
    let headFont = 7;
    let cellPadding = COMPACT_CELL_PADDING;
    let minCellHeight = 4.6;
    if (rowCount > 12) {
        fontSize = 5.5;
        headFont = 6;
        cellPadding = { top: 1, right: 1, bottom: 1, left: 1 };
        minCellHeight = 3.2;
    } else if (rowCount > 8) {
        fontSize = 6;
        headFont = 6.5;
        cellPadding = { top: 1.1, right: 1.1, bottom: 1.1, left: 1.1 };
        minCellHeight = 3.5;
    }
    return { fontSize, headFont, cellPadding, minCellHeight };
};

const formatMedTreatEntry = (item, isArabic = false) => {
    if (item.itemType === 'medication') {
        const steroidRegimen = isTopicalSteroidMedication(item)
            ? `Steroid regimen: ${formatSteroidRegimen(item, isArabic)}`
            : '';
        const medInstructions = formatMedicationInstructionsForPdf(item, isArabic);
        return [
            item.name || 'Medication',
            item.genericName || item.generic || '',
            [item.frequency, item.duration].filter(Boolean).join(' | '),
            steroidRegimen,
            medInstructions,
            item.notes || '',
        ].filter(Boolean).join(' | ');
    }

    return [
        item.surgical_treatment || item.surgicalTreatment ? 'Surgical Plan' : 'Medical Treatment',
        item.medical_treatment || item.medicalTreatment || '',
        item.surgical_treatment || item.surgicalTreatment || '',
        item.investigations ? `Investigations: ${item.investigations}` : '',
        item.followup_date || item.followupDate ? `Follow-up: ${item.followup_date || item.followupDate}` : '',
        item.notes || '',
    ].filter(Boolean).join(' | ');
};

const medTreatOtherSummaryRow = (item, isArabic = false) => [
    formatMedTreatDate(item),
    item.itemType === 'medication' ? 'Medication' : item.itemType === 'surgical' ? 'Surgical' : 'Treatment',
    formatMedTreatEntry(item, isArabic),
];

/**
 * Generate the current Medications & Treatments section/list as one A5 PDF.
 * Single-patient lists: one Rx-style medication table (all meds) first when present,
 * then a Date / Type / Details table for non-medication rows. Mixed-patient lists
 * keep the global Date / Patient / Type / Details table.
 */
export const generateMedicationsTreatmentsPDF = async (items = [], title = 'Medications & Treatments', options = {}) => {
    const { forPrint = false, returnDoc = false, isArabic = false, patientId: optPatientId = null, referenceId: optReferenceId = null } = options;
    const doc = createPdfDoc();
    const pageWidth = doc.internal.pageSize.getWidth();
    const centerX = getContentCenterX(pageWidth);
    const contentWidth = getContentWidth(pageWidth);
    const t = (key) => translations[isArabic ? 'ar' : 'en'][key] || key;

    addHeader(doc, pageWidth, isArabic);
    doc.setCharSpace(0);
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    doc.text(title.toUpperCase(), centerX, 50, { align: 'center', maxWidth: contentWidth, charSpace: 0 });
    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    doc.text(`Printed: ${new Date().toLocaleString()}`, PRINT_MARGIN_LEFT, 59, { maxWidth: contentWidth, charSpace: 0 });

    let lastTableFinalY = null;
    const printedLineBottomY = 59 + 7;
    let tableStartY = 72;

    const runMixedPatientTable = () => {
        const lay = getMedTreatSummaryTableLayout(items.length);
        autoTable(doc, {
            startY: tableStartY,
            head: [[
                isArabic ? 'التاريخ' : 'Date',
                isArabic ? 'المريض' : 'Patient',
                isArabic ? 'النوع' : 'Type',
                isArabic ? 'التفاصيل' : 'Details',
            ]],
            body: items.map((item) => [
                formatMedTreatDate(item),
                item.patientName || 'Unknown Patient',
                item.itemType === 'medication' ? (isArabic ? 'دواء' : 'Medication')
                    : item.itemType === 'surgical' ? (isArabic ? 'جراحي' : 'Surgical')
                        : (isArabic ? 'علاج' : 'Treatment'),
                formatMedTreatEntry(item, isArabic),
            ]),
            theme: 'grid',
            tableWidth: contentWidth,
            headStyles: {
                ...compactHeadStyles(lay.headFont),
                fontSize: lay.headFont,
                cellPadding: lay.cellPadding,
            },
            styles: {
                fontSize: lay.fontSize,
                cellPadding: lay.cellPadding,
                minCellHeight: lay.minCellHeight,
                valign: 'top',
                overflow: 'ellipsize',
            },
            columnStyles: {
                0: { cellWidth: 19 },
                1: { cellWidth: 25 },
                2: { cellWidth: 18 },
                3: { cellWidth: contentWidth - 62 },
            },
            margin: getPdfTableMargins(doc),
        });
        lastTableFinalY = doc.lastAutoTable?.finalY ?? null;
    };

    if (items?.length > 0) {
        const samePatient = allMedTreatItemsSamePatient(items);
        const p0 = samePatient ? items[0] : null;
        const portalPatientId = samePatient && p0
            ? coalescePdfPatientReferenceId(
                p0,
                {
                    name: p0.patientName,
                    patientName: p0.patientName,
                    id: p0.patientId ?? p0.patient_id,
                    patientId: p0.patientId ?? p0.patient_id,
                },
                { patientId: optPatientId, referenceId: optReferenceId },
            )
            : (optPatientId ?? optReferenceId ?? null);

        if (samePatient) {
            tableStartY = (await addPatientInfoBlock(
                doc,
                {
                    name: p0.patientName,
                    patientName: p0.patientName,
                    id: portalPatientId,
                    patientId: portalPatientId,
                },
                PRINT_MARGIN_LEFT,
                printedLineBottomY + 2,
                {
                    isArabic,
                    pageWidth,
                    recordDate: new Date().toISOString().split('T')[0],
                    patientId: portalPatientId,
                    referenceId: portalPatientId,
                    sourceRecord: p0,
                }
            )) + 4;
            const medications = items.filter((i) => i.itemType === 'medication');
            const nonMedications = items.filter((i) => i.itemType !== 'medication');
            let nextY = tableStartY;

            if (medications.length > 0) {
                const layout = getMedicationTableLayout(medications.length, contentWidth);
                const [cw0, cw1, cw2, cw3] = layout.columnWidths;
                const medBody = medications.map((med, idx) => buildMedicationPdfTableRow(med, idx, isArabic));

                autoTable(doc, {
                    startY: nextY,
                    head: [[
                        '#',
                        t('medication'),
                        t('frequency'),
                        t('duration'),
                    ]],
                    body: medBody,
                    theme: 'grid',
                    tableWidth: contentWidth,
                    styles: {
                        fontSize: layout.bodyFont,
                        cellPadding: layout.cellPadding,
                        overflow: 'linebreak',
                        minCellHeight: layout.minCellHeight,
                        valign: 'top',
                    },
                    headStyles: {
                        ...neutralMedicationHeadStyles(layout.headFont),
                        fontSize: layout.headFont,
                        cellPadding: layout.cellPadding,
                    },
                    bodyStyles: {
                        fontSize: layout.bodyFont,
                        cellPadding: layout.cellPadding,
                        overflow: 'linebreak',
                        minCellHeight: layout.minCellHeight,
                        valign: 'top',
                    },
                    columnStyles: {
                        0: { cellWidth: cw0, halign: 'center' },
                        1: { cellWidth: cw1, overflow: 'linebreak' },
                        2: { cellWidth: cw2, overflow: 'linebreak' },
                        3: { cellWidth: cw3, halign: 'center', overflow: 'linebreak' },
                    },
                    margin: getPdfTableMargins(doc),
                });
                lastTableFinalY = doc.lastAutoTable?.finalY ?? null;
                nextY = lastTableFinalY + 6;

                const hasMedNotes = medications.some(isTopicalSteroidMedication)
                    || collectVisitLevelInstructions(medications, options).length > 0;
                if (hasMedNotes) {
                    nextY = appendMedicationPdfNotes(doc, medications, nextY, contentWidth, {
                        dense: medications.length > 6,
                        isArabic,
                        visitInstructions: options.visitInstructions,
                    });
                    lastTableFinalY = nextY;
                    nextY += 4;
                }
            }

            if (nonMedications.length > 0) {
                const lay = getMedTreatSummaryTableLayout(nonMedications.length);
                const dateW = 19;
                const typeW = 18;
                const detailsW = Math.max(20, contentWidth - dateW - typeW);
                autoTable(doc, {
                    startY: nextY,
                    head: [[
                        isArabic ? 'التاريخ' : 'Date',
                        isArabic ? 'النوع' : 'Type',
                        isArabic ? 'التفاصيل' : 'Details',
                    ]],
                    body: nonMedications.map((row) => medTreatOtherSummaryRow(row, isArabic)),
                    theme: 'grid',
                    tableWidth: contentWidth,
                    headStyles: {
                        ...compactHeadStyles(lay.headFont),
                        fontSize: lay.headFont,
                        cellPadding: lay.cellPadding,
                    },
                    styles: {
                        fontSize: lay.fontSize,
                        cellPadding: lay.cellPadding,
                        minCellHeight: lay.minCellHeight,
                        valign: 'top',
                        overflow: 'ellipsize',
                    },
                    columnStyles: {
                        0: { cellWidth: dateW },
                        1: { cellWidth: typeW },
                        2: { cellWidth: detailsW },
                    },
                    margin: getPdfTableMargins(doc),
                });
                lastTableFinalY = doc.lastAutoTable?.finalY ?? null;
            }
        } else {
            runMixedPatientTable();
        }

        await finalizePatientReportPdf(doc, pageWidth, isArabic, portalPatientId, lastTableFinalY ?? 72);
    } else {
        await finalizePatientReportPdf(doc, pageWidth, isArabic, null, 72);
    }

    const safeTitle = title.replace(/[^a-z0-9_-]+/gi, '_').toLowerCase();
    const fileName = `${safeTitle}_${Date.now()}.pdf`;
    return emitPdfResult(doc, fileName, { forPrint, returnDoc });
};

