/**
 * Generate a generic report PDF with Arabic support (single A5 page, clinical sections only).
 */
export const generateReportPDF = async (report, patientName, options = {}) => {
    const { isArabic = false, forPrint = false, returnDoc = false, patientId = null, referenceId = null } = options;
    const portalId = coalescePdfPatientReferenceId(report, patientName, { patientId, referenceId });
    const patientForPdf = normalizePatientArgForPdf(patientName, portalId);
    const doc = createPdfDoc();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const centerX = getContentCenterX(pageWidth);
    const contentWidth = getContentWidth(pageWidth);
    const footerY = pageHeight - 10;
    const maxBodyY = footerY - 6;

    addCompactReportHeader(doc, pageWidth, isArabic);

    const rawTitle = report.title || report.type || 'Medical Report';
    const localizedTitle = isArabic
        ? translateReportDocumentTitle(rawTitle, 'ar')
        : rawTitle;
    const reportTitle = localizedTitle.toUpperCase();
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text(reportTitle, centerX, 27, { align: 'center', maxWidth: contentWidth });

    const dateLabel = isArabic ? 'التاريخ:' : 'Date:';
    const idLabel = isArabic ? 'رقم المريض:' : 'Patient ID:';
    const reportDate = report.date || new Date().toISOString().split('T')[0];
    doc.setFontSize(9.5);
    doc.setFont('helvetica', 'normal');
    const metaLine = [
        `${isArabic ? 'المريض:' : 'Patient:'} ${getPatientName(patientForPdf)}`,
        portalId ? `${idLabel} ${portalId}` : '',
        `${dateLabel} ${reportDate}`,
    ]
        .filter(Boolean)
        .join('   ·   ');
    doc.text(metaLine, PRINT_MARGIN_LEFT, 32, { maxWidth: contentWidth });

    let currentY = 36;
    let bodyFontSize = 10;
    let lineStep = 4.2;
    let sectionTitleSize = 10.5;
    let sectionGap = 1.8;

    const pdfBlocks = report.pdfBlocks?.length ? report.pdfBlocks : null;
    const reportContent =
        report.content ||
        (report.sections
            ? Object.entries(report.sections)
                  .filter(([, value]) => String(value || '').trim())
                  .map(([section, value]) => `${section}\n${value}`)
                  .join('\n\n')
            : '');
    const bodyText = reportContent || report.summary || '';

    const estimateHeight = (blocks) => {
        let h = 0;
        const measure = (blocksToMeasure, fontSize, step) => {
            doc.setFontSize(fontSize);
            blocksToMeasure.forEach((block) => {
                if (block.title) h += sectionTitleSize * 0.35 + sectionGap;
                const lines = doc.splitTextToSize(String(block.body || ''), contentWidth);
                h += lines.length * step + sectionGap;
            });
        };
        if (blocks?.length) measure(blocks, bodyFontSize, lineStep);
        else if (bodyText) {
            const lines = doc.splitTextToSize(bodyText, contentWidth);
            h += lines.length * lineStep;
        }
        if (report.signature?.trim()) h += 12;
        return h;
    };

    const blocksForLayout =
        pdfBlocks?.length ? pdfBlocks : bodyText ? [{ title: null, body: bodyText }] : [];
    while (currentY + estimateHeight(blocksForLayout) > maxBodyY && bodyFontSize > 8.5) {
        bodyFontSize -= 0.5;
        lineStep -= 0.25;
        sectionTitleSize -= 0.3;
        sectionGap -= 0.15;
    }

    const renderBlock = (blockTitle, blockBody) => {
        if (!String(blockBody || '').trim()) return;
        if (blockTitle) {
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(sectionTitleSize);
            doc.text(blockTitle, PRINT_MARGIN_LEFT, currentY);
            currentY += sectionTitleSize * 0.35 + sectionGap * 0.5;
        }
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(bodyFontSize);
        doc.splitTextToSize(String(blockBody), contentWidth).forEach((line) => {
            if (currentY > maxBodyY) return;
            doc.text(line, PRINT_MARGIN_LEFT, currentY);
            currentY += lineStep;
        });
        currentY += sectionGap;
    };

    if (pdfBlocks?.length) {
        pdfBlocks.forEach((block) => renderBlock(block.title || null, block.body));
    } else if (bodyText) {
        renderBlock(null, bodyText);
    } else if (report.doctorNotes?.trim()) {
        renderBlock(isArabic ? 'ملاحظات إضافية' : 'Additional Notes', report.doctorNotes);
    }

    if (
        currentY < maxBodyY - 18 &&
        isReportSectionIncluded(REPORT_SECTION_INCLUSION_KEYS.SIGNATURE, report?.sectionInclusion)
    ) {
        currentY = await addPhysicianSignatureToPdf(doc, pageWidth, currentY + 2, {
            isArabic,
            align: 'right',
            marginRight: PRINT_MARGIN_RIGHT,
            maxY: maxBodyY,
        });
    }

    doc.setFontSize(8);
    doc.setTextColor(100);
    doc.text(`Tel: ${CLINIC_INFO.phone}`, centerX, footerY - 4, { align: 'center', maxWidth: contentWidth });
    doc.text(
        isArabic ? CLINIC_INFO.addressAr : CLINIC_INFO.address,
        centerX,
        footerY,
        { align: 'center', maxWidth: contentWidth }
    );
    doc.setTextColor(0);

    const fileName = `report_${getPatientFileName(patientForPdf)}_${report.id || Date.now()}.pdf`;
    return emitPdfResult(doc, fileName, { forPrint, returnDoc });
};

export const printReportPDF = async (report, patientName, isArabicOrOptions = false) => {
    const opts = mergeArabicOrPdfOptions(isArabicOrOptions);
    const { reportNeedsHtmlExport, printReportHtml } = await import('./reportPdfExport');
    if (reportNeedsHtmlExport(report, opts.isArabic)) {
        return printReportHtml(report, patientName, opts);
    }
    return generateReportPDF(report, patientName, { ...opts, forPrint: true });
};

export const downloadReportPDF = async (report, patientName, isArabicOrOptions = false) => {
    const opts = mergeArabicOrPdfOptions(isArabicOrOptions);
    const { reportNeedsHtmlExport, downloadReportHtml } = await import('./reportPdfExport');
    if (reportNeedsHtmlExport(report, opts.isArabic)) {
        return downloadReportHtml(report, patientName, opts);
    }
    return generateReportPDF(report, patientName, { ...opts, forPrint: false });
};

const formatRecordValue = (value) => {
    if (value === null || value === undefined || value === '') return '-';
    if (Array.isArray(value)) return value.join(', ');
    if (typeof value === 'object') {
        return Object.entries(value)
            .map(([key, nestedValue]) => `${key}: ${formatRecordValue(nestedValue)}`)
            .join(' | ');
    }
    return String(value);
};

const humanizeKey = (key) => key
    .replace(/_/g, ' ')
    .replace(/([A-Z])/g, ' $1')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/^./, (char) => char.toUpperCase());

const cleanRecordEntries = (record) => Object.entries(record || {})
    .filter(([key]) => ![
        'id',
        'patientId',
        'patient_id',
        'patientID',
        'patientName',
        'referenceId',
        'dob',
        'dateOfBirth',
        'birthDate',
        'age',
        'contact',
        'phone',
        'phoneNumber',
        'mobile',
        'mobileNumber',
        '_dirty',
        '_deleted',
        '_lastLocalChangeAt'
    ].includes(key))
    .map(([key, value]) => [humanizeKey(key), formatRecordValue(value)]);

export const generateGenericRecordPDF = async (record, options = {}) => {
    const {
        title = 'CLINIC RECORD',
        subtitle = '',
        patientName = record?.patientName || '',
        forPrint = false,
        returnDoc = false,
        filePrefix = 'clinic_record',
        patientId = record?.patientId || null,
        referenceId = null,
        isArabic = false,
        recordDate: recordDateOption = null,
    } = options;
    const doc = createPdfDoc();
    const pageWidth = doc.internal.pageSize.getWidth();
    const centerX = getContentCenterX(pageWidth);
    const contentWidth = getContentWidth(pageWidth);

    addHeader(doc, pageWidth, isArabic);

    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text(title.toUpperCase(), centerX, 52, { align: 'center', maxWidth: contentWidth });

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    let yAfterTitle = 60;
    if (subtitle) {
        doc.text(subtitle, centerX, yAfterTitle, { align: 'center', maxWidth: contentWidth });
        yAfterTitle += 8;
    }

    const resolvedPatientId = coalescePdfPatientReferenceId(record, patientName, {
        patientId: patientId != null && String(patientId).trim() !== '' ? patientId : null,
        referenceId: referenceId != null && String(referenceId).trim() !== '' ? referenceId : null,
    });
    const nameStr = typeof patientName === 'string' ? patientName : (patientName?.name || patientName?.patientName || '');
    const hasPatientContext = Boolean((nameStr && String(nameStr).trim()) || resolvedPatientId);
    const patientForBlock = normalizePatientArgForPdf(patientName, resolvedPatientId);
    const recordDate =
        recordDateOption
        || record?.date
        || (typeof record?.createdAt === 'string' ? record.createdAt.split('T')[0] : '')
        || record?.dateScheduled
        || new Date().toISOString().split('T')[0];

    let tableStartY;
    if (hasPatientContext) {
        tableStartY = await addPatientInfoBlock(doc, patientForBlock, PRINT_MARGIN_LEFT, yAfterTitle + 2, {
            isArabic,
            pageWidth,
            recordDate,
            patientId: resolvedPatientId,
            referenceId: resolvedPatientId,
            sourceRecord: record,
        }) + 4;
    } else {
        tableStartY = yAfterTitle + 4;
    }

    doc.text(`Printed: ${new Date().toLocaleString()}`, PRINT_MARGIN_LEFT, tableStartY, { maxWidth: contentWidth });
    tableStartY += 8;

    autoTable(doc, {
        startY: tableStartY,
        head: [['Field', 'Value']],
        body: cleanRecordEntries(record),
        theme: 'grid',
        headStyles: compactHeadStyles(8),
        styles: { ...compactTableStyles(8), valign: 'top' },
        columnStyles: {
            0: { cellWidth: 35, fontStyle: 'bold' },
            1: { cellWidth: contentWidth - 35 },
        },
        margin: getPdfTableMargins(doc),
    });

    await finalizePatientReportPdf(
        doc,
        pageWidth,
        isArabic,
        resolvedPatientId,
        doc.lastAutoTable?.finalY ?? tableStartY
    );

    const safeTitle = filePrefix.replace(/[^a-z0-9_-]+/gi, '_').toLowerCase();
    const fileName = `${safeTitle}_${record?.id || Date.now()}.pdf`;
    return emitPdfResult(doc, fileName, { forPrint, returnDoc });
};

export const printGenericRecordPDF = (record, options = {}) => {
    return generateGenericRecordPDF(record, { ...options, forPrint: true });
};

export const downloadGenericRecordPDF = (record, options = {}) => {
    return generateGenericRecordPDF(record, { ...options, forPrint: false });
};

